import fs from "node:fs";
import net from "node:net";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
vi.mock("node:child_process", () => ({
    fork: vi.fn().mockReturnValue({
        unref: vi.fn(),
        pid: 12345,
    }),
}));
// Don't let the opportunistic zombie sweep touch real dev daemons during tests.
vi.mock("./scope.js", () => ({
    sweepZombieDaemons: vi.fn(),
}));
import { fork } from "node:child_process";
import { buildMatches, ensureDaemon, waitForLockHolderDaemon, } from "./ensure.js";
function tmpPath(prefix) {
    return path.join(os.tmpdir(), `bitfab-test-${prefix}-${Date.now()}-${Math.random().toString(36).slice(2)}`);
}
function pathsFor(socketPath, pidPath) {
    return { socketPath, pidPath, metaPath: null, worktreeRoot: null };
}
describe("buildMatches", () => {
    it("matches when the daemon reports our exact build", () => {
        expect(buildMatches("abc123", "abc123")).toBe(true);
    });
    it("does not match a different reported build", () => {
        expect(buildMatches("abc123", "def456")).toBe(false);
    });
    it("does not match a daemon that reports NO build (the stale-daemon hole)", () => {
        // A daemon too old to answer `build` on ping must be reaped, not reused:
        // this is the exact case that let a 2-day-old daemon keep serving old code.
        expect(buildMatches("abc123", null)).toBe(false);
    });
    it("accepts anything when our own build is unknowable (no respawn loop)", () => {
        expect(buildMatches("unknown", null)).toBe(true);
        expect(buildMatches("unknown", "anything")).toBe(true);
    });
});
describe("ensureDaemon", () => {
    let socketPath;
    let pidPath;
    let mockServer = null;
    beforeEach(() => {
        vi.clearAllMocks();
        vi.spyOn(fs, "existsSync").mockReturnValue(true);
        socketPath = `${tmpPath("ensure")}.sock`;
        pidPath = `${tmpPath("ensure")}.pid`;
    });
    afterEach(() => {
        if (mockServer) {
            mockServer.close();
            mockServer = null;
        }
        try {
            fs.unlinkSync(socketPath);
        }
        catch { }
        try {
            fs.unlinkSync(pidPath);
        }
        catch { }
        try {
            fs.unlinkSync(`${socketPath}.lock`);
        }
        catch { }
    });
    it("spawns daemon when PID file is missing", async () => {
        // Make fork actually start a mock server so waitForSocket succeeds
        vi.mocked(fork).mockImplementation(() => {
            mockServer = net.createServer((socket) => {
                let buffer = "";
                socket.on("data", (chunk) => {
                    buffer += chunk.toString();
                    if (buffer.includes("\n")) {
                        socket.write('{"ok":true}\n');
                        buffer = "";
                    }
                });
            });
            mockServer.listen(socketPath);
            return { unref: vi.fn(), pid: 12345 };
        });
        await ensureDaemon(pathsFor(socketPath, pidPath));
        expect(fork).toHaveBeenCalledOnce();
    });
    it("reuses daemon when PID is alive and socket responds", async () => {
        // Write a PID file with current process PID (so it's "alive")
        fs.writeFileSync(pidPath, `${process.pid}\n`);
        // Start a mock server that responds to ping
        mockServer = net.createServer((socket) => {
            let buffer = "";
            socket.on("data", (chunk) => {
                buffer += chunk.toString();
                if (buffer.includes("\n")) {
                    socket.write('{"ok":true}\n');
                    buffer = "";
                }
            });
        });
        await new Promise((resolve) => {
            mockServer.listen(socketPath, resolve);
        });
        await ensureDaemon(pathsFor(socketPath, pidPath));
        expect(fork).not.toHaveBeenCalled();
    });
    it("cleans up stale PID file and respawns", async () => {
        // Write PID file with a dead PID
        fs.writeFileSync(pidPath, "999999999\n");
        vi.mocked(fork).mockImplementation(() => {
            mockServer = net.createServer((socket) => {
                let buffer = "";
                socket.on("data", (chunk) => {
                    buffer += chunk.toString();
                    if (buffer.includes("\n")) {
                        socket.write('{"ok":true}\n');
                        buffer = "";
                    }
                });
            });
            mockServer.listen(socketPath);
            return { unref: vi.fn(), pid: 12345 };
        });
        await ensureDaemon(pathsFor(socketPath, pidPath));
        expect(fork).toHaveBeenCalledOnce();
    });
});
describe("waitForLockHolderDaemon", () => {
    let socketPath;
    let mockServer = null;
    // Mutable build the mock daemon reports on ping; null = don't report a build.
    let reportedBuild = "LOCAL";
    function startMockDaemon() {
        mockServer = net.createServer((socket) => {
            let buffer = "";
            socket.on("data", (chunk) => {
                buffer += chunk.toString();
                if (buffer.includes("\n")) {
                    const payload = reportedBuild === null
                        ? { ok: true }
                        : { ok: true, build: reportedBuild };
                    socket.write(`${JSON.stringify(payload)}\n`);
                    buffer = "";
                }
            });
        });
        return new Promise((resolve) => {
            mockServer.listen(socketPath, resolve);
        });
    }
    beforeEach(() => {
        socketPath = `${tmpPath("wait")}.sock`;
        reportedBuild = "LOCAL";
    });
    afterEach(() => {
        if (mockServer) {
            mockServer.close();
            mockServer = null;
        }
        try {
            fs.unlinkSync(socketPath);
        }
        catch { }
    });
    it("waits until the answering daemon reports the local build", async () => {
        reportedBuild = "STALE";
        await startMockDaemon();
        // Flip to the matching build partway through the wait. The waiter must NOT
        // return on the initial stale pings - that's the build-mismatch window.
        let switchedAt = 0;
        setTimeout(() => {
            reportedBuild = "LOCAL";
            switchedAt = Date.now();
        }, 300);
        const startedAt = Date.now();
        await waitForLockHolderDaemon(socketPath, 5000, "LOCAL");
        const returnedAt = Date.now();
        expect(switchedAt).toBeGreaterThan(0);
        // Returned only after the build started matching, never on a stale ping.
        expect(returnedAt).toBeGreaterThanOrEqual(switchedAt);
        expect(returnedAt - startedAt).toBeGreaterThanOrEqual(250);
    });
    it("falls back to returning (not throwing) when the build never matches", async () => {
        reportedBuild = "STALE";
        await startMockDaemon();
        const startedAt = Date.now();
        // Build never matches local, but a daemon is responding: return after the
        // timeout instead of throwing (the rare cross-install respawn race).
        await expect(waitForLockHolderDaemon(socketPath, 600, "LOCAL")).resolves.toBeUndefined();
        expect(Date.now() - startedAt).toBeGreaterThanOrEqual(550);
    });
    it("does not return early for a daemon that reports no build", async () => {
        // A daemon reporting no build is treated as a mismatch (it can't be our
        // build), so the waiter must not accept it: it falls back to returning only
        // at the deadline (a daemon is responding, just not a build-verified one).
        reportedBuild = null;
        await startMockDaemon();
        const startedAt = Date.now();
        await expect(waitForLockHolderDaemon(socketPath, 600, "LOCAL")).resolves.toBeUndefined();
        expect(Date.now() - startedAt).toBeGreaterThanOrEqual(550);
    });
    it("returns on first alive ping when the local build is unknown", async () => {
        reportedBuild = "STALE";
        await startMockDaemon();
        const startedAt = Date.now();
        await waitForLockHolderDaemon(socketPath, 5000, "unknown");
        // No build gating when local build can't be computed: returns promptly.
        expect(Date.now() - startedAt).toBeLessThan(1000);
    });
    it("throws when no daemon ever answers", async () => {
        await expect(waitForLockHolderDaemon(socketPath, 500, "LOCAL")).rejects.toThrow(/did not become ready/);
    });
    it("throws if the daemon answered earlier but is dead at the deadline", async () => {
        // A wrong-build daemon answers initially, then disappears (the lock holder
        // reaped it and hasn't bound the replacement yet). The waiter must NOT claim
        // readiness off the earlier success: re-ping at the deadline finds it dead.
        reportedBuild = "STALE";
        await startMockDaemon();
        setTimeout(() => {
            if (mockServer) {
                mockServer.close();
                mockServer = null;
            }
        }, 250);
        await expect(waitForLockHolderDaemon(socketPath, 700, "LOCAL")).rejects.toThrow(/did not become ready/);
    });
});
